    // "50% IN" / "0% OUT" / "100% BUBBLE"
    function (s) { var m = s.match(/^(\d+)% (IN|OUT|BUBBLE)$/); if (!m) return null;
      var t = {IN:"DENTRO", OUT:"FORA", BUBBLE:"BOLHA"}; return m[1] + "% " + t[m[2]]; },
